rules.pseudocode:
if ate == 1:
    R = M * r_food
else:
    R = c_step

for each action a in available_actions:
    if a == 'eat' or a is a move toward food:
        Q_tilde[a] = M * Q[s, a]
    else:
        Q_tilde[a] = Q[s, a]
P(a) = exp(beta * Q_tilde[a]) / sum(exp(beta * Q_tilde[j]) for j in available_actions)
sample action from P
